use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Read, Seek};

struct BinaryValidator {
    expected_magic: u32,
}

impl BinaryValidator {
    fn new(magic_number: u32) -> Self {
        BinaryValidator { expected_magic: magic_number }
    }

    fn validate_binary(&self, path: &str) -> io::Result<bool> {
        let mut file = File::open(path)?;
        let mut buffer = [0u8; 4];
        file.read_exact(&mut buffer)?; 
        let magic = u32::from_le_bytes(buffer);

        if magic != self.expected_magic {
            return Ok(false);
        }

        let mut map: HashMap<String, String> = HashMap::new();
        let mut current_offset = 0;

        file.seek(io::SeekFrom::Current(0))?; 

        let metadata = std::fs::metadata(path).map_err(|e| io::Error::new(io::ErrorKind::NotFound, e))?;
        let file_size = metadata.len() as usize;

        println!("Binary passed magic check. Size: {} bytes.", file_size);
        Ok(true)
    }
}

fn main() -> io::Result<()> {
    let validator = BinaryValidator::new(0x7f61b2c4);
    let result = validator.validate_binary("test_elf.bin")?;

    if result {
        println!("Successfully loaded and validated the instruction set.");
    } else {
        eprintln!("Validation failed: Incorrect file signature detected.");
    }
    Ok(())
}
